_add("capex_cycle_assessment", "Capex Cycle Assessment", "Position in network/content investment cycle (build vs harvest).", "Carriers in 5G build (peak capex) vs harvest (FCF expansion). Streaming in content build vs library leverage.", "Trend in capex/revenue + content/revenue", "comm_quality")
_add("rule_of_40_assessment", "Rule-of-40 Verdict", "Pass/fail grade for digital subsegments.", "Applies to streaming, internet platforms, social, and growth-stage gaming. Less applicable to carriers/agencies/broadcasters.", "Rule40 band", "comm_quality")
_add("unit_economics", "Unit Economics", "Summary of ARPU, churn, CPGA.", "Sustainable subscriber economics: low churn × high ARPU × controlled CPGA = compounding. Negative on any axis = thesis risk.", "ARPU, Churn, CPGA composite", "comm_quality")
_add("sbc_risk_assessment", "SBC Risk", "Stock-based compensation risk framing.", "Concentrated in internet/social/gaming. Mature carriers and agencies near zero. Categories: Contained / Moderate / High / Severe.", "SBC / Revenue band", "comm_quality")
_add("platform_position", "Platform Position", "Scale/network/ecosystem position.", "Big Internet (GOOGL, META) and tier-1 carriers (TMUS, VZ) compound for decades. Sub-scale challengers face structural pressure.", "Tier + sub-sector + market share", "comm_quality")
