_add("revenue_predictability", "Revenue Predictability", "Subscription/contract mix vs ad-cyclical.", ">60% subscription = predictable (carriers, streaming-mature, cable broadband). >70% ad = cyclical (Meta, GOOGL, broadcasters).", "Revenue mix decomposition", "comm_quality")

